// @ts-nocheck
import React, { useMemo, useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { RefreshCw, Activity, Skull, Filter, Gauge } from 'lucide-react';
import { api } from '../../lib/api';
import { notify, notifyError, confirm } from '../../lib/notify';
import { openQueryStoreTab } from '../../store/workspace';
import { useQueryStoreNavStore } from '../../store/query-store-nav';
import { sqlFromProcessRow } from '../../lib/query-store-sql';
import { ConnectionBreakdownBar } from '../../components/monitor/ConnectionBreakdownCard';
import { findDbColumn, rowDatabaseName } from '../../lib/connection-breakdown';
import { AiAnalysisButton } from '../../components/ai/AiAnalysisButton';
import { ExportButtons } from '../../components/ui/ExportButtons';
import { useVerticalSplit } from '../../lib/usePanelResize';
import { isLiteEdition } from '../../lib/config';

function hasProcessSql(sql) {
  const s = String(sql ?? '').trim();
  return s.length >= 4 && s.toLowerCase() !== 'null';
}

function fmtDuration(val) {
  const sec = Number(val);
  if (!Number.isFinite(sec) || sec < 0) return String(val ?? '');
  if (sec < 60) return `${sec}s`;
  if (sec < 3600) return `${Math.floor(sec / 60)}m ${sec % 60}s`;
  return `${Math.floor(sec / 3600)}h ${Math.floor((sec % 3600) / 60)}m`;
}

const PROCESS_CMD_FILTER_KEY = 'nv-process-cmd-excluded';

function readExcludedCommands() {
  try {
    const raw = localStorage.getItem(PROCESS_CMD_FILTER_KEY);
    if (!raw) return new Set(['Sleep']);
    const arr = JSON.parse(raw);
    return new Set(Array.isArray(arr) ? arr : ['Sleep']);
  } catch {
    return new Set(['Sleep']);
  }
}

function rowCommand(row, commandCol) {
  const raw = row?.[commandCol] ?? row?.Command ?? row?.command ?? row?.state ?? '';
  const s = String(raw ?? '').trim();
  return s || '—';
}

function CommandFilterBar({ commands, excluded, onToggle, onShowAll, onHideNoise }) {
  if (!commands.length) return null;
  const hiddenCount = commands.filter((c) => excluded.has(c.name)).length;
  return (
    <div className="shrink-0 px-2 py-1.5 border-b border-nv-border bg-nv-panel/50 flex flex-wrap items-center gap-1.5">
      <span className="text-2xs text-nv-textSubtle flex items-center gap-1 shrink-0">
        <Filter size={11} className="text-sky-500" />
        Command
      </span>
      {commands.map(({ name, count }) => {
        const hidden = excluded.has(name);
        return (
          <button
            key={name}
            type="button"
            onClick={() => onToggle(name)}
            className={`px-2 py-0.5 rounded-full text-2xs border transition-colors ${
              hidden
                ? 'border-nv-border bg-nv-bg/40 text-nv-textMuted line-through opacity-60'
                : 'border-nv-accent/50 bg-nv-selected text-nv-accentDark hover:bg-nv-selected'
            }`}
            title={hidden ? `Mostrar ${name}` : `Ocultar ${name}`}
          >
            {name}
            <span className="ml-1 tabular-nums opacity-70">{count}</span>
          </button>
        );
      })}
      <div className="flex items-center gap-1 ml-auto shrink-0">
        <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={onShowAll} title="Mostrar todos los commands">
          Todos
        </button>
        <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={onHideNoise} title="Ocultar Sleep, Daemon y Connect">
          Sin ruido
        </button>
        {hiddenCount > 0 && (
          <span className="text-2xs text-nv-textMuted">{hiddenCount} oculto{hiddenCount === 1 ? '' : 's'}</span>
        )}
      </div>
    </div>
  );
}

function openInQueryStore(connectionId, connectionName, sql) {
  const text = String(sql ?? '').trim();
  if (!hasProcessSql(text)) {
    notify('Este proceso no tiene SQL en Info/query (p. ej. Sleep o Daemon).');
    return;
  }
  openQueryStoreTab({ connectionId, connectionName });
  useQueryStoreNavStore.getState().openQuery({ connectionId, sqlText: text });
}

export function ProcessListPanel({ connectionId, connectionName }) {
  const [autoRefresh, setAutoRefresh] = useState(false);
  const [sort, setSort] = useState(null);
  const [excludedCommands, setExcludedCommands] = useState(readExcludedCommands);
  const [selectedDatabases, setSelectedDatabases] = useState(() => new Set());
  const [selectedUsers, setSelectedUsers] = useState(() => new Set());

  const { data: rows = [], isFetching, refetch, error } = useQuery({
    queryKey: ['processlist', connectionId],
    queryFn: () => api.processlist(connectionId),
    refetchInterval: autoRefresh ? 3000 : false,
    refetchIntervalInBackground: false,
    retry: false,
  });

  const killMutation = useMutation({
    mutationFn: (id) => api.killProcess(connectionId, id),
    onSuccess: () => refetch(),
  });

  const { data: engineUsers = [] } = useQuery({
    queryKey: ['engine-users', connectionId],
    queryFn: () => api.engineUsers(connectionId),
    staleTime: 60000,
    retry: false,
  });

  const cols = rows[0] ? Object.keys(rows[0]) : [];
  const idCol = cols.find((c) => c === 'Id') ?? cols.find((c) => c === 'pid') ?? cols.find((c) => /^p?id$/i.test(c)) ?? cols[0];
  const timeCol = cols.find((c) => c === 'Time' || c === 'time' || c === 'duration');
  const userCol = cols.find((c) => c === 'User' || c === 'user') ?? 'User';
  const commandCol = cols.find((c) => c === 'Command' || c === 'command' || c === 'state') ?? 'Command';
  const dbCol = useMemo(() => findDbColumn(rows), [rows]);

  const toggleDatabaseFilter = (name) => {
    setSelectedDatabases((prev) => {
      const next = new Set(prev);
      if (next.has(name)) next.delete(name);
      else next.add(name);
      if (next.size === 0) setSelectedUsers(new Set());
      return next;
    });
  };

  const clearDatabaseFilters = () => {
    setSelectedDatabases(new Set());
    setSelectedUsers(new Set());
  };

  const toggleUserFilter = (name) => {
    setSelectedUsers((prev) => {
      const next = new Set(prev);
      if (next.has(name)) next.delete(name);
      else next.add(name);
      return next;
    });
  };

  const clearUserFilters = () => setSelectedUsers(new Set());

  const availableCommands = useMemo(() => {
    const counts = new Map();
    for (const r of rows) {
      const name = rowCommand(r, commandCol);
      counts.set(name, (counts.get(name) ?? 0) + 1);
    }
    return [...counts.entries()]
      .sort((a, b) => b[1] - a[1])
      .map(([name, count]) => ({ name, count }));
  }, [rows, commandCol]);

  const usersInFilteredDbs = useMemo(() => {
    if (!selectedDatabases.size) return [];
    const counts = new Map();
    for (const r of rows) {
      if (!selectedDatabases.has(rowDatabaseName(r, dbCol))) continue;
      const u = String(r?.[userCol] ?? '—');
      counts.set(u, (counts.get(u) ?? 0) + 1);
    }
    return [...counts.entries()]
      .sort((a, b) => b[1] - a[1])
      .map(([name, count]) => ({ name, count }));
  }, [rows, selectedDatabases, dbCol, userCol]);

  const userConnLimit = useMemo(() => {
    const map = new Map();
    for (const u of engineUsers) {
      const name = String(u?.User ?? u?.username ?? u?.user ?? '');
      if (!name) continue;
      // MySQL: max_user_connections (simultaneous), max_connections_per_hour
      const muc = Number(u?.max_user_connections);
      const mcph = Number(u?.max_connections_per_hour);
      // PostgreSQL: connection_limit (rolconnlimit, -1 = unlimited)
      const cl = u?.connection_limit != null ? Number(u?.connection_limit) : Number(u?.rolconnlimit);
      const prev = map.get(name);
      const next = {
        maxUserConnections: Number.isFinite(muc) && muc > 0 ? Math.max(prev?.maxUserConnections ?? 0, muc) : prev?.maxUserConnections ?? null,
        maxConnectionsPerHour: Number.isFinite(mcph) && mcph > 0 ? Math.max(prev?.maxConnectionsPerHour ?? 0, mcph) : prev?.maxConnectionsPerHour ?? null,
        connectionLimit: Number.isFinite(cl) && cl >= 0 ? cl : prev?.connectionLimit ?? null,
      };
      map.set(name, next);
    }
    return map;
  }, [engineUsers]);

  const formatUserLimit = (name) => {
    const lim = userConnLimit.get(name);
    if (!lim) return null;
    if (lim.maxUserConnections != null) return { value: lim.maxUserConnections, title: `max_user_connections = ${lim.maxUserConnections} (conexiones simultáneas)` };
    if (lim.connectionLimit != null) return { value: lim.connectionLimit, title: `CONNECTION LIMIT = ${lim.connectionLimit}` };
    if (lim.maxConnectionsPerHour != null) return { value: `${lim.maxConnectionsPerHour}/h`, title: `max_connections_per_hour = ${lim.maxConnectionsPerHour}` };
    return null;
  };

  const sorted = useMemo(() => {
    let base = rows;
    if (excludedCommands.size) {
      base = base.filter((r) => !excludedCommands.has(rowCommand(r, commandCol)));
    }
    if (selectedDatabases.size) {
      base = base.filter((r) => selectedDatabases.has(rowDatabaseName(r, dbCol)));
      if (selectedUsers.size) {
        base = base.filter((r) => selectedUsers.has(String(r?.[userCol] ?? '—')));
      }
    }
    if (!sort) return base;
    return [...base].sort((a, b) => {
      const va = sort.col === '__duration__' ? a[timeCol] : a[sort.col];
      const vb = sort.col === '__duration__' ? b[timeCol] : b[sort.col];
      const na = Number(va);
      const nb = Number(vb);
      let cmp;
      if (!Number.isNaN(na) && !Number.isNaN(nb)) cmp = na - nb;
      else cmp = String(va ?? '').localeCompare(String(vb ?? ''));
      return sort.dir === 'asc' ? cmp : -cmp;
    });
  }, [rows, sort, excludedCommands, commandCol, selectedDatabases, dbCol, selectedUsers, userCol]);

  const persistExcluded = (next) => {
    setExcludedCommands(next);
    try {
      localStorage.setItem(PROCESS_CMD_FILTER_KEY, JSON.stringify([...next]));
    } catch {
      /* ignore */
    }
  };

  const toggleCommandFilter = (name) => {
    const next = new Set(excludedCommands);
    if (next.has(name)) next.delete(name);
    else next.add(name);
    persistExcluded(next);
  };

  const showAllCommands = () => persistExcluded(new Set());

  const hideNoiseCommands = () => {
    const noise = new Set(['Sleep', 'Daemon', 'Connect', 'Binlog Dump', 'Connect Out']);
    const next = new Set();
    for (const { name } of availableCommands) {
      if (noise.has(name)) next.add(name);
    }
    persistExcluded(next);
  };

  const allCols = timeCol ? [...cols, '__duration__'] : cols;
  const displayName = connectionName ?? connectionId;

  const toggleSort = (col) => {
    setSort((prev) => {
      if (!prev || prev.col !== col) return { col, dir: 'asc' };
      if (prev.dir === 'asc') return { col, dir: 'desc' };
      return null;
    });
  };

  const onKill = async (id) => {
    if (id == null || id === '') return;
    if (!(await confirm(`Kill process ${id}?`, 'Kill Process'))) return;
    try {
      await killMutation.mutateAsync(id);
    } catch (e) {
      notifyError(e, 'Kill failed');
    }
  };

  const bodySplit = useVerticalSplit(34, { minPct: 12, maxPct: 80, mobileStack: true });

  return (
    <div className="h-full flex flex-col min-h-0 bg-nv-bg">
      <div className="flex items-center gap-2 px-2 py-1 bg-nv-toolbar border-b border-nv-border shrink-0">
        <span className="font-semibold text-xs">Process List</span>
        <span className="text-2xs text-nv-textSubtle">
          ({sorted.length}{sorted.length !== rows.length ? ` / ${rows.length}` : ''})
        </span>
        <label className="flex items-center gap-1 text-2xs text-nv-textSubtle ml-3 cursor-pointer">
          <input type="checkbox" checked={autoRefresh} onChange={(e) => setAutoRefresh(e.target.checked)} />
          Auto-refresh
        </label>
        <AiAnalysisButton
          connectionId={connectionId}
          kind="processlist"
          identifier="processlist"
          title="Análisis con IA — Process List"
          titleAttr="Analizar la lista de procesos con IA (triage y recomendaciones)"
        />
        <ExportButtons rows={sorted} filenamePrefix={`processlist-${connectionName ?? connectionId}`} />
        <button type="button" onClick={() => refetch()} className="ml-auto nv-btn">
          {isFetching ? <RefreshCw size={11} className="animate-spin" /> : <RefreshCw size={11} />}
          {' '}Refresh
        </button>
      </div>

      {error && (
        <div className="p-3 text-xs text-red-400 flex gap-2 shrink-0">
          {String(error.message)}
        </div>
      )}

      <div className="flex-1 min-h-0 flex flex-col" ref={bodySplit.containerRef}>
        <div
          className={bodySplit.stacked ? 'shrink-0' : 'flex flex-col min-h-0 overflow-y-auto'}
          style={bodySplit.stacked ? undefined : { height: `${bodySplit.topPct}%` }}
        >
          <ConnectionBreakdownBar
            rows={rows}
            loading={isFetching && !rows.length}
            selectedDatabases={selectedDatabases}
            onToggleDatabase={toggleDatabaseFilter}
            onClearDatabases={clearDatabaseFilters}
          />

          {selectedDatabases.size > 0 && usersInFilteredDbs.length > 0 && (
            <div className="shrink-0 px-2 py-1.5 border-b border-nv-border bg-nv-panel/50 flex flex-wrap items-center gap-1.5">
              <span className="text-2xs text-nv-textSubtle shrink-0">Users</span>
              {usersInFilteredDbs.map(({ name, count }) => {
                const active = selectedUsers.has(name);
                const lim = formatUserLimit(name);
                return (
                  <button
                    key={name}
                    type="button"
                    onClick={() => toggleUserFilter(name)}
                    className={`px-2 py-0.5 rounded-full text-2xs border transition-colors inline-flex items-center gap-1 ${
                      active
                        ? 'border-violet-500 bg-violet-700/60 text-white'
                        : 'border-nv-border bg-nv-panel text-nv-textSubtle hover:bg-nv-hover'
                    }`}
                    title={active ? `Quitar filtro de ${name}` : `Filtrar conexiones de ${name} (${count})${lim ? ` · ${lim.title}` : ''}`}
                  >
                    {name}
                    <span className="tabular-nums opacity-80">— {count}</span>
                    {lim && (
                      <span
                        className="ml-0.5 inline-flex items-center gap-0.5 px-1 rounded-full bg-amber-900/70 text-amber-200 border border-amber-700/60 text-2xs font-semibold tabular-nums"
                        title={lim.title}
                      >
                        <Gauge size={10} />
                        {lim.value}
                      </span>
                    )}
                  </button>
                );
              })}
              {selectedUsers.size > 0 && (
                <button type="button" className="nv-btn !py-0.5 !text-2xs ml-auto shrink-0" onClick={clearUserFilters}>
                  Limpiar
                </button>
              )}
            </div>
          )}

          <CommandFilterBar
            commands={availableCommands}
            excluded={excludedCommands}
            onToggle={toggleCommandFilter}
            onShowAll={showAllCommands}
            onHideNoise={hideNoiseCommands}
          />
        </div>

        {!bodySplit.stacked && (
          <div
            className="resizer horizontal shrink-0"
            onMouseDown={bodySplit.onResizeStart}
            title="Arrastrar para ajustar altura"
          />
        )}

        <div className="flex-1 min-h-0 overflow-auto">
          <table className="w-full text-xs">
          <thead className="sticky top-0 bg-nv-gridHeader border-b border-nv-border z-10">
            <tr>
              <th className="min-w-[8.5rem] px-1 py-1.5 text-2xs text-nv-textSubtle">Actions</th>
              {allCols.map((col) => (
                <th
                  key={col}
                  onClick={() => toggleSort(col)}
                  className="text-left px-2 py-1.5 font-semibold border-r border-nv-borderLight select-none text-2xs cursor-pointer hover:bg-nv-hover"
                  title={col === '__duration__' ? 'Sort by duration' : `Sort by ${col}`}
                >
                  {col === '__duration__' ? 'Duration' : col}
                  {sort?.col === col ? (sort.dir === 'asc' ? ' ▲' : ' ▼') : ''}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.length === 0 && rows.length > 0 && (
              <tr>
                <td colSpan={allCols.length + 1} className="px-3 py-8 text-center text-nv-textMuted text-2xs">
                {selectedDatabases.size > 0 ? (
                  selectedUsers.size > 0 ? (
                    <>Ningún proceso del/los usuario(s) seleccionado(s) en la/s DB(s) filtrada(s) — pulsa <strong>Limpiar</strong> en los chips.</>
                  ) : (
                    <>Ningún proceso en {selectedDatabases.size === 1 ? 'la base seleccionada' : 'las bases seleccionadas'} — pulsa <strong>Limpiar</strong> en los chips.</>
                  )
                ) : (
                  <>Ningún proceso coincide con el filtro de Command — pulsa <strong>Todos</strong> o activa algún tipo.</>
                )}
                </td>
              </tr>
            )}
            {sorted.map((row, i) => {
              const sql = sqlFromProcessRow(row);
              const canQs = hasProcessSql(sql);
              return (
                <tr key={`${row[idCol] ?? i}-${i}`} className="hover:bg-nv-hover border-b border-nv-borderLight">
                  <td className="px-1 py-0.5 whitespace-nowrap">
                    <div className="inline-flex items-center gap-1">
                      {!isLiteEdition && (
                        <button
                          type="button"
                          className="nv-btn !py-0.5 !text-2xs whitespace-nowrap disabled:opacity-35"
                          title={canQs ? 'Abrir en Query Store' : 'Sin SQL — solo procesos Query/Execute tienen texto'}
                          disabled={!canQs}
                          onClick={() => openInQueryStore(connectionId, displayName, sql)}
                        >
                          <Activity size={10} className="text-sky-500 shrink-0" />
                          Query Store
                        </button>
                      )}
                      <button
                        type="button"
                        onClick={() => onKill(row[idCol])}
                        title={`Kill ${row[idCol]}`}
                        className="nv-btn !py-0.5 !px-1 text-red-400 hover:text-red-300 disabled:opacity-30"
                        disabled={row[idCol] == null}
                      >
                        <Skull size={11} />
                      </button>
                    </div>
                  </td>
                  {allCols.map((col) => (
                    <td
                      key={col}
                      className="px-2 py-0.5 font-mono text-2xs border-r border-nv-borderLight max-w-sm truncate"
                      title={col !== '__duration__' ? String(row[col] ?? '') : fmtDuration(row[timeCol])}
                    >
                      {col === '__duration__' ? (
                        <span className="text-sky-400 font-semibold">{fmtDuration(row[timeCol])}</span>
                      ) : row[col] == null ? (
                        <span className="text-nv-textMuted italic">NULL</span>
                      ) : (
                        String(row[col] ?? '')
                      )}
                    </td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
        </div>
      </div>
    </div>
  );
}
